#!/usr/bin/env python3
# Piece 1c-B-cabinet (dream-os) — binder-native dashboard read endpoint.
#
# B, step 1: the foundation the new home + list screens paint from. A NEW
# endpoint GET /api/v2/vendor/cabinet/:vendorId — context.js is left UNTOUCHED
# so nothing currently rendering breaks. Returns the six vendor-native slices
# (clients, leads, paid, owed, booked, reminders) + every binder in FULL so the
# PWA hood-lift can show the raw record. Reads binders like Kriya does; reads
# events for the calendar slices. Curl-verifiable before any front-end work.

import base64, os, sys
ROOT = os.getcwd()
CAB_B64 = ""

CORE = os.path.join(ROOT, "src", "api", "vendor", "core.js")
MOUNT_ANCHOR = "router.use('/context',  require('./context'));"
MOUNT_NEW    = ("router.use('/context',  require('./context'));\n"
                "router.use('/cabinet',  require('./cabinet'));")

def main():
    vdir = os.path.join(ROOT, "src", "api", "vendor")
    if not os.path.isdir(vdir):
        print("ERROR: run from dream-os repo root."); sys.exit(1)

    # 1. drop the endpoint
    open(os.path.join(vdir, "cabinet.js"), "wb").write(base64.b64decode(CAB_B64))
    print("OK: wrote src/api/vendor/cabinet.js")

    # 2. mount it next to context (idempotent, anchor-guarded)
    s = open(CORE, encoding="utf-8").read()
    if "require('./cabinet')" in s:
        print("SKIP: /cabinet already mounted in core.js")
    elif MOUNT_ANCHOR in s:
        open(CORE, "w", encoding="utf-8").write(s.replace(MOUNT_ANCHOR, MOUNT_NEW, 1))
        print("OK: mounted /cabinet in core.js")
    else:
        print("WARN: context mount anchor not found — mount /cabinet by hand in core.js"); sys.exit(1)

    print("\nPiece 1c-B-cabinet written. Curl GET /api/v2/vendor/cabinet/:vendorId to verify the six slices.")

if __name__ == "__main__":
    main()
